159→function formatConversationEntities(entities: ConversationEntity[]): string {
160→  if (entities.length === 0) {
161→    return "- none";
162→  }
163→
164→  return entities
165→    .slice(0, 20)
166→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
167→    .join("\n");
168→}
169→
170→
171→function formatRelevantEntities(entities: RankedEntity[]): string {
172→  return entities
173→    .map((e) => `- ${e.kind}: ${e.name} (relevance ${e.score.toFixed(2)})`)
174→    .join("\n");
175→}
