391→
392→  if (context.discussedEntity) {
393→    const entity = context.discussedEntity;
394→    sections.push(
395→      "## Discussed Entity",
396→      "The user opened this conversation to discuss a specific entity.",
397→      `- Kind: ${entity.kind}`,
398→      `- Name: ${entity.name}`,
399→      ...(entity.status ? [`- Status: ${entity.status}`] : []),
400→      "Acknowledge this entity in your first response and help the user with their question about it.",
401→      "",
